create table auditoria (entidad_id bigint, fecha datetime(6), id bigint not null auto_increment, accion varchar(255), detalle varchar(255), entidad varchar(255), usuario varchar(255), primary key (id)) engine=InnoDB;
create table categoria (id bigint not null auto_increment, nombre varchar(255) not null, primary key (id)) engine=InnoDB;
create table consumo_inventario (cantidad integer, fecha datetime(6), id bigint not null auto_increment, insumo_id bigint, pedido_id bigint, primary key (id)) engine=InnoDB;
create table detalle_pedido (cantidad integer not null, precio_unitario decimal(12,2) not null, subtotal decimal(12,2) not null, id bigint not null auto_increment, pedido_id bigint, producto_id bigint not null, primary key (id)) engine=InnoDB;
create table factura (total decimal(12,2) not null, fecha datetime(6) not null, id bigint not null auto_increment, pedido_id bigint not null, primary key (id)) engine=InnoDB;
create table insumo (id bigint not null auto_increment, nombre varchar(255) not null, unidad varchar(255) not null, primary key (id)) engine=InnoDB;
create table inventario (stock integer not null, fecha_creacion datetime(6) not null, fecha_modificacion datetime(6) not null, id bigint not null auto_increment, insumo_id bigint not null, primary key (id)) engine=InnoDB;
create table lote_insumo (cantidad_disponible integer not null, cantidad_inicial integer not null, fecha_ingreso datetime(6) not null, fecha_vencimiento datetime(6) not null, id bigint not null auto_increment, insumo_id bigint not null, estado enum ('ACTIVO','AGOTADO','VENCIDO') not null, ubicacion enum ('BODEGA','COCINA') not null, primary key (id)) engine=InnoDB;
create table mesa (activa bit not null, capacidad integer, numero integer not null, id bigint not null auto_increment, mesero_id bigint, estado enum ('CUENTA_PEDIDA','DISPONIBLE','OCUPADA') not null, primary key (id)) engine=InnoDB;
create table pago (monto decimal(12,2) not null, fecha_pago datetime(6) not null, id bigint not null auto_increment, pedido_id bigint not null, comprobante_url varchar(255), metodo enum ('EFECTIVO','TARJETA','TRANSFERENCIA') not null, primary key (id)) engine=InnoDB;
create table password_reset_tokens (used bit not null, created_at DATETIME(6) DEFAULT CURRENT_TIMESTAMP(6) not null, expires_at datetime(6) not null, id bigint not null auto_increment, persona_id bigint not null, code varchar(10) not null, primary key (id)) engine=InnoDB;
create table pedido (total decimal(12,2) not null, cliente_id bigint, fecha datetime(6) not null, id bigint not null auto_increment, mesa_id bigint, mesero_id bigint, estado enum ('CANCELADO','CONFIRMADO','CREADO','CUENTA_PEDIDA','ENTREGADO','EN_PREPARACION','LISTO','PAGADO') not null, tipo enum ('DOMICILIO','MESA') not null, primary key (id)) engine=InnoDB;
create table persona (acepto_habeas_data bit not null, activo bit not null, fecha_nacimiento date, intentos_fallidos integer, salario float(53), bloqueado_hasta datetime(6), created_at datetime(6), fecha_aceptacion datetime(6), id bigint not null auto_increment, reset_token_expiration datetime(6), updated_at datetime(6), contrasena varchar(255) not null, direccion_envio varchar(255), email varchar(255) not null, nombre varchar(255), numero_identificacion varchar(255), reset_token varchar(255), telefono varchar(255), rol enum ('ADMINISTRADOR','CLIENTE','COCINERO','MESERO') not null, primary key (id)) engine=InnoDB;
create table producto (activo bit not null, precio decimal(10,2) not null, categoria_id bigint not null, created_at datetime(6), id bigint not null auto_increment, updated_at datetime(6), descripcion varchar(500) not null, nombre varchar(255) not null, primary key (id)) engine=InnoDB;
